mapper.select:
SELECT t.id,t.goods_id,t.goods_create_by,t.erp_order_id,t.create_at,t.order_sn,t.shop_num
FROM (
    SELECT
    MAX(l.id) as id,
    l.goods_id,
    MAX(l.goods_create_by) as goods_create_by,
    l.erp_order_id,
    MAX(l.create_at) as create_at,
    MAX(g.order_sn) as order_sn,
    COUNT(DISTINCT l.shop_id) as shop_num
    FROM synchronization_shop_log l
    LEFT JOIN erp_goods_order g ON l.erp_order_id = g.id
    WHERE 1=1

        AND l.goods_id = #{goodsId}


        AND l.goods_create_by = #{goodsCreateBy}


        AND l.erp_order_id = #{erpOrderId}


        AND g.order_sn LIKE CONCAT('%', #{orderSn}, '%')


        AND l.shop_id = #{shopId}


        AND l.shop_name LIKE CONCAT('%', #{shopName}, '%')


        AND l.shop_create_by = #{shopCreateBy}


        AND l.platform_id = #{platformId}


        AND l.code = #{code}


        AND (l.shop_create_by = #{userId} OR l.goods_create_by = #{userId})

    GROUP BY l.erp_order_id, l.goods_id
    ORDER BY MAX(l.create_at) DESC
    LIMIT #{pageNum}, #{pageSize}
) t
ORDER BY t.create_at DESC

SELECT COUNT(*)
FROM (
SELECT 1
FROM synchronization_shop_log l
LEFT JOIN erp_goods_order g ON l.erp_order_id = g.id


        AND l.goods_id = #{goodsId}


        AND l.goods_create_by = #{goodsCreateBy}


        AND l.erp_order_id = #{erpOrderId}


        AND g.order_sn LIKE CONCAT('%', #{orderSn}, '%')


        AND l.shop_id = #{shopId}


        AND l.shop_name LIKE CONCAT('%', #{shopName}, '%')


        AND l.shop_create_by = #{shopCreateBy}


        AND l.platform_id = #{platformId}


        AND l.code = #{code}


GROUP BY l.erp_order_id, l.goods_id
) AS grouped_result

SELECT

FROM synchronization_shop_log


        AND id = #{id}


        AND goods_id = #{goodsId}


        AND goods_create_by = #{goodsCreateBy}


        AND erp_order_id = #{erpOrderId}


        AND order_sn LIKE CONCAT('%', #{orderSn}, '%')


        AND shop_id = #{shopId}


        AND shop_name LIKE CONCAT('%', #{shopName}, '%')


        AND shop_create_by = #{shopCreateBy}


        AND platform_id = #{platformId}


        AND code = #{code}


ORDER BY create_at DESC

